    const password = 'Mongolfiera' + row.Nome.charAt(0).toUpperCase() + row.Cognome.charAt(0).toUpperCase() + '!!';
    await storeValue('migrazione_row', {...row, password: password});
    const res = await creaUtenteAPI.run();
    if (!res || !res.data || !res.data.id) {
      showAlert('Errore creazione utente: ' + row.Email, 'error');
      return;
    }
    await collegaUtenteContattoAPI.run();
    await this.init();
    showAlert('Utente creato: ' + row.Email, 'success');
  }
}

